import { useRef, useEffect } from 'react';
import { AudioEngine, AUDIO_MSE_CAPABLE } from './AudioEngine';

// ── Global singleton：同一时刻只允许一路音频播放 ──────────────────────────────
let _active = null; // { audioEl, eng, stop }

function _stopGlobal() {
  if (!_active) return;
  const { audioEl, eng, stop } = _active;
  stop?.();
  eng?.destroy();
  audioEl.pause();
  _active = null;
}

/**
 * useAudioPlayer
 *
 * 封装音频 MSE 分片播放的全部逻辑，含全局单例互斥。
 *
 * @param {string}  audioSrc   音频 URL
 * @param {boolean} isActive   是否应当播放（由外部 activeAudioId === id 决定）
 * @returns {{ audioRef, syncReady }}
 *   syncReady: Promise，resolve 时音频已可播放，供 A/V Sync 使用
 */
export function useAudioPlayer({ audioSrc, isActive }) {
  const audioRef      = useRef(null);
  const engRef        = useRef(null);
  const syncReadyRef  = useRef(null); // { resolve, reject }
  const syncPromise   = useRef(new Promise((res, rej) => { syncReadyRef.current = { resolve: res, reject: rej }; }));

  // ── Bootstrap AudioEngine（仅一次，src 变化时重建）────────────────────────
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !audioSrc) return;

    // 重置 syncPromise
    syncPromise.current = new Promise((res, rej) => { syncReadyRef.current = { resolve: res, reject: rej }; });

    if (AUDIO_MSE_CAPABLE) {
      const eng = new AudioEngine(audio, audioSrc);
      engRef.current = eng;

      const onTime = () => eng.onTime();
      audio.addEventListener('timeupdate', onTime);

      eng.start()
        .then(() => { syncReadyRef.current?.resolve(audio); })
        .catch(e  => { syncReadyRef.current?.reject(e); });

      return () => {
        audio.removeEventListener('timeupdate', onTime);
        eng.destroy();
        engRef.current = null;
        if (_active && _active.audioEl === audio) _active = null;
      };
    } else {
      // Native fallback
      audio.src = audioSrc;
      const onCanPlay = () => syncReadyRef.current?.resolve(audio);
      audio.addEventListener('canplay', onCanPlay, { once: true });
      return () => {
        audio.removeEventListener('canplay', onCanPlay);
        audio.pause();
        audio.removeAttribute('src');
        audio.load();
        if (_active && _active.audioEl === audio) _active = null;
      };
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [audioSrc]);

  // ── isActive 控制播放 / 暂停 ───────────────────────────────────────────────
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !audioSrc) return;

    if (isActive) {
      let cancelled = false;

      syncPromise.current.then(a => {
        if (cancelled) return;
        _stopGlobal();
        _active = { audioEl: a, eng: engRef.current, stop: null };
        a.play().catch(() => {});
      }).catch(() => {});

      return () => {
        cancelled = true;
        if (_active && _active.audioEl === audio) {
          audio.pause();
          _active = null;
        }
      };
    } else {
      if (_active && _active.audioEl === audio) {
        audio.pause();
        _active = null;
      }
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isActive, audioSrc]);

  return { audioRef, syncPromise: syncPromise.current };
}

/**
 * 供 A/V Sync 层调用：强制停止当前全局音频
 */
export { _stopGlobal as stopGlobalAudio };
